import { Component, OnInit } from '@angular/core';
import { RouterLink } from '@angular/router';
import { ProductService } from '../../core/services/product.service';
import { Product } from '../../core/models/product.model';
import { ProductCardComponent } from '../../components/product-card/product-card.component';

@Component({
  selector: 'app-home',
  standalone: true,
  imports: [RouterLink, ProductCardComponent],
  styleUrl: './home.component.scss',
  template: `
    <!-- Hero -->
    <section class="hero">
      <div class="hero-content">
        <span class="label-tag">New Collection — 2025</span>
        <h1 class="hero-title">Wear Your<br>Identity</h1>
        <p class="hero-sub">Tunisian luxury streetwear. Limited pieces, unlimited expression.</p>
        <a routerLink="/shop" class="btn-primary">Explore the Collection</a>
      </div>
      <div class="hero-image">
        <div class="hero-img-placeholder">
          <span>MEEZAJ</span>
        </div>
      </div>
    </section>

    <!-- Featured Products -->
    <section class="section-products">
      <div class="container">
        <div class="section-header">
          <span class="label-tag">The Collection</span>
          <h2>Featured Pieces</h2>
          <div class="divider"></div>
        </div>
        @if (loading) {
          <div class="loading-grid">
            @for (n of skeletons; track n) {
              <div class="skeleton"></div>
            }
          </div>
        } @else if (featured.length) {
          <div class="products-grid">
            @for (product of featured; track product.id) {
              <app-product-card [product]="product" />
            }
          </div>
        } @else {
          <div class="empty-state">
            <p>Collection coming soon.</p>
            <a routerLink="/shop" class="btn-outline" style="margin-top:1.5rem">View All</a>
          </div>
        }
        <div class="section-footer">
          <a routerLink="/shop" class="btn-outline">View All Pieces</a>
        </div>
      </div>
    </section>

    <!-- Brand Story -->
    <section class="section-story">
      <div class="container">
        <div class="story-grid">
          <div class="story-image">
            <div class="story-img-placeholder"></div>
          </div>
          <div class="story-content">
            <span class="label-tag">Our Story</span>
            <h2>Born in Tunisia,<br>Made for the World</h2>
            <div class="divider"></div>
            <p>
              MEEZAJ is more than a brand — it's a statement. Each piece is designed
              to fuse Tunisian heritage with contemporary streetwear aesthetics.
              Limited runs, premium materials, and a story sewn into every stitch.
            </p>
            <a href="#" class="btn-outline" style="margin-top:2rem">Learn More</a>
          </div>
        </div>
      </div>
    </section>

    <!-- Material Callout -->
    <section class="section-callout">
      <div class="container">
        <div class="callout-grid">
          <div class="callout-item">
            <span class="callout-icon">◇</span>
            <h3>Premium Materials</h3>
            <p>Sourced locally and internationally for lasting quality.</p>
          </div>
          <div class="callout-item">
            <span class="callout-icon">◇</span>
            <h3>Limited Editions</h3>
            <p>Small runs ensure exclusivity. Once gone, gone forever.</p>
          </div>
          <div class="callout-item">
            <span class="callout-icon">◇</span>
            <h3>Free Shipping</h3>
            <p>On all orders above 100 TND within Tunisia.</p>
          </div>
        </div>
      </div>
    </section>
  `
})
export class HomeComponent implements OnInit {
  featured: Product[] = [];
  loading = true;
  skeletons = [1, 2, 3, 4];

  constructor(private productService: ProductService) {}

  ngOnInit(): void {
    this.productService.getFeatured().subscribe({
      next: (products) => {
        this.featured = products;
        this.loading = false;
      },
      error: () => {
        this.loading = false;
      }
    });
  }
}
